    href: string;
    title: string;
    image: string;
    description?: string;
    imageAlt?: string;
    date?: string;
    datetime?: string;
    author?: Author;
    ctaText?: string;
    className?: string;
    variant?: 'default' | 'compact';
};

function ArticleCard({
    href,
    title,
